        Assert.That.DoesNotStartWith(result, "-");
    }

    [TestMethod]
    public void GenerateSlug_DoesNotEndWithDash()
    {
        var result = _formatter.GenerateSlug("---Hello---");

        Assert.That.DoesNotEndWith(result, "-");
    }

    [TestMethod]
    public void GenerateSlug_WhitespaceInput_ThrowsArgumentException()
    {
        Assert.ThrowsExactly<ArgumentException>(
            () => _formatter.GenerateSlug("   "));
    }

